1	import 'dart:convert';
2	import 'package:audioplayers/audioplayers.dart';
3	import 'package:flutter/material.dart';
4	import 'package:http/http.dart' as http;
5	import '../services/api_service.dart';
6	import 'profile_screen.dart';
7	import 'settings_screen.dart';
8	import 'voice_note_recorder.dart';
9	
10	class UserCard {
11	  final int id;
12	  final String username;
13	  final int? age;
14	  final String? sex;
15	  final String? photoUrl;
16	
17	  UserCard({
18	    required this.id,
19	    required this.username,
20	    this.age,
21	    this.sex,
22	    this.photoUrl,
23	  });
24	
25	  factory UserCard.fromJson(Map<String, dynamic> json) {
26	    return UserCard(
27	      id: json['id'] as int,
28	      username: json['username'] as String,
29	      age: json['age'] as int?,
30	      sex: json['sex'] as String?,
31	      photoUrl: json['photo_url'] as String?,
32	    );
33	  }
34	}
35	
36	/// Lightweight model used inside the ranking modal.
37	class _RankItem {
38	  final int id;
39	  final String username;
40	  final int? age;
41	  final String? sex;
42	
43	  _RankItem({
44	    required this.id,
45	    required this.username,
46	    this.age,
47	    this.sex,
48	  });
49	}
50	
51	class UsersScreen extends StatefulWidget {
52	  const UsersScreen({super.key});
53	
54	  @override
55	  State<UsersScreen> createState() => _UsersScreenState();
56	}
57	
58	class _UsersScreenState extends State<UsersScreen> {
59	  static const String _baseUrl = 'http://10.0.2.2:8000';
60	
61	  final List<UserCard> _users = [];
62	  final ScrollController _scrollController = ScrollController();
63	  final Set<int> _likedIds = {};
64	  final Set<int> _blockedIds = {};
65	
66	  int _page = 1;
67	  static const int _perPage = 30;
68	  bool _isLoading = false;
69	  bool _hasMore = true;
70	  String? _token;
71	  String? _errorMessage;
72	
73	  @override
74	  void initState() {
75	    super.initState();
76	    _init();
77	    _scrollController.addListener(_onScroll);
78	  }
79	
80	  @override
81	  void dispose() {
82	    _scrollController.dispose();
83	    super.dispose();
84	  }
85	
86	  Future<void> _init() async {
87	    _token = await ApiService.getToken();
88	    await _loadUsers();
89	  }
90	
91	  void _onScroll() {
92	    if (_scrollController.position.pixels >=
93	        _scrollController.position.maxScrollExtent - 200) {
94	      if (!_isLoading && _hasMore) {
95	        _loadUsers();
96	      }
97	    }
98	  }
99	
100	  Future<void> _loadUsers() async {
101	    if (_isLoading || !_hasMore) return;
102	    setState(() {
103	      _isLoading = true;
104	      _errorMessage = null;
105	    });
106	
107	    try {
108	      final headers = <String, String>{
109	        'Content-Type': 'application/json',
110	      };
111	      if (_token != null) {
112	        headers['Authorization'] = 'Bearer $_token';
113	      }
114	
115	      final uri = Uri.parse(
116	          '$_baseUrl/api/users?page=$_page&per_page=$_perPage');
117	      final response = await http.get(uri, headers: headers);
118	
119	      if (response.statusCode == 200) {
120	        final data = jsonDecode(response.body) as Map<String, dynamic>;
121	        final List<dynamic> rawUsers = data['users'] as List<dynamic>;
122	        final newUsers =
123	            rawUsers.map((u) => UserCard.fromJson(u as Map<String, dynamic>)).toList();
124	        setState(() {
125	          _users.addAll(newUsers);
126	          _hasMore = data['has_more'] as bool;
127	          _page++;
128	          _isLoading = false;
129	        });
130	      } else {
131	        setState(() {
132	          _errorMessage = 'Error ${response.statusCode}: ${response.body}';
133	          _isLoading = false;
134	        });
135	      }
136	    } catch (e) {
137	      setState(() {
138	        _errorMessage = 'Network error: $e';
139	        _isLoading = false;
140	      });
141	    }
142	  }
143	
144	  // ── Fetch current who-i-like list ─────────────────────────────────────────
145	
146	  Future<List<_RankItem>> _fetchWhoILike() async {
147	    try {
148	      final resp = await http.get(
149	        Uri.parse('$_baseUrl/api/who_i_like'),
150	        headers: {
151	          'Content-Type': 'application/json',
152	          if (_token != null) 'Authorization': 'Bearer $_token',
153	        },
154	      );
155	      if (resp.statusCode == 200) {
156	        final data = jsonDecode(resp.body) as Map<String, dynamic>;
157	        final users = (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
158	        return users.map((u) => _RankItem(
159	          id: u['id'] as int,
160	          username: u['username'] as String,
161	          age: u['age'] as int?,
162	          sex: u['sex'] as String?,
163	        )).toList();
164	      }
165	    } catch (_) {}
166	    return [];
167	  }
168	
169	  // ── Save re-ranking ───────────────────────────────────────────────────────
170	
171	  Future<void> _saveRerank(List<_RankItem> ranked) async {
172	    try {
173	      final rankings = ranked.asMap().entries.map((e) {
174	        return {'username': e.value.username, 'rank': e.key + 1};
175	      }).toList();
176	      await http.put(
177	        Uri.parse('$_baseUrl/api/like/rerank'),
178	        headers: {
179	          'Content-Type': 'application/json',
180	          if (_token != null) 'Authorization': 'Bearer $_token',
181	        },
182	        body: jsonEncode({'rankings': rankings}),
183	      );
184	    } catch (_) {}
185	  }
186	
187	  // ── Show ranking bottom sheet ─────────────────────────────────────────────
188	
189	  Future<void> _showRankingSheet(UserCard newUser, List<_RankItem> currentLikes) async {
190	    // Build initial list: existing likes + newly liked person at bottom
191	    final items = [
192	      ...currentLikes,
193	      _RankItem(
194	        id: newUser.id,
195	        username: newUser.username,
196	        age: newUser.age,
197	        sex: newUser.sex,
198	      ),
199	    ];
200	
201	    final saved = await showModalBottomSheet<bool>(
202	      context: context,
203	      isScrollControlled: true,
204	      backgroundColor: const Color(0xFF0E0E0E),
205	      shape: const RoundedRectangleBorder(
206	        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
207	      ),
208	      builder: (ctx) => _RankingSheet(
209	        items: items,
210	        newUserId: newUser.id,
211	        baseUrl: _baseUrl,
212	        token: _token,
213	        onSave: (reordered) async {
214	          await _saveRerank(reordered);
215	          Navigator.of(ctx).pop(true);
216	        },
217	      ),
218	    );
219	
220	    if (saved == true) {
221	      // Remove the liked card from the grid
222	      setState(() {
223	        _likedIds.add(newUser.id);
224	        _users.removeWhere((u) => u.id == newUser.id);
225	      });
226	    }
227	  }
228	
229	  // ── Like / unlike ─────────────────────────────────────────────────────────
230	
231	  Future<void> _uploadVoiceNote(int likedUserId, String filePath) async {
232	    try {
233	      final request = http.MultipartRequest(
234	        'POST',
235	        Uri.parse('$_baseUrl/api/like/$likedUserId/voice'),
236	      );
237	      if (_token != null) {
238	        request.headers['Authorization'] = 'Bearer $_token';
239	      }
240	      request.files.add(await http.MultipartFile.fromPath(
241	        'file',
242	        filePath,
243	        filename: 'voice_note.m4a',
244	      ));
245	      await request.send();
246	    } catch (_) {}
247	  }
248	
249	  Future<void> _likeUser(UserCard user) async {
250	    if (_likedIds.contains(user.id)) {
251	      // Unlike
252	      try {
253	        await http.delete(
254	          Uri.parse('$_baseUrl/api/like/${user.id}'),
255	          headers: {
256	            'Content-Type': 'application/json',
257	            if (_token != null) 'Authorization': 'Bearer $_token',
258	          },
259	        );
260	        setState(() => _likedIds.remove(user.id));
261	      } catch (_) {}
262	      return;
263	    }
264	
265	    // Step 1: Show voice recorder before any API calls
266	    if (!mounted) return;
267	    final audioPath = await showModalBottomSheet<String>(
268	      context: context,
269	      isScrollControlled: true,
270	      backgroundColor: Colors.transparent,
271	      builder: (ctx) => VoiceNoteRecorder(username: user.username),
272	    );
273	
274	    // User dismissed without completing a recording
275	    if (audioPath == null) return;
276	
277	    // Step 2: POST like
278	    try {
279	      final resp = await http.post(
280	        Uri.parse('$_baseUrl/api/like'),
281	        headers: {
282	          'Content-Type': 'application/json',
283	          if (_token != null) 'Authorization': 'Bearer $_token',
284	        },
285	        body: jsonEncode({'liked_user_id': user.id}),
286	      );
287	      if (resp.statusCode == 201 || resp.statusCode == 200) {
288	        // Step 3: Upload voice note
289	        await _uploadVoiceNote(user.id, audioPath);
290	
291	        // Step 4: Fetch current like list and show ranking sheet
292	        final currentLikes = await _fetchWhoILike();
293	        final withoutNew = currentLikes.where((u) => u.id != user.id).toList();
294	
295	        if (!mounted) return;
296	        await _showRankingSheet(user, withoutNew);
297	      }
298	    } catch (e) {
299	      if (mounted) {
300	        ScaffoldMessenger.of(context).showSnackBar(
301	          SnackBar(content: Text('Like failed: $e')),
302	        );
303	      }
304	    }
305	  }
306	
307	  Future<void> _blockUser(int userId) async {
308	    try {
309	      final resp = await http.post(
310	        Uri.parse('$_baseUrl/api/block'),
311	        headers: {
312	          'Content-Type': 'application/json',
313	          if (_token != null) 'Authorization': 'Bearer $_token',
314	        },
315	        body: jsonEncode({'blocked_user_id': userId}),
316	      );
317	      if (resp.statusCode == 201 || resp.statusCode == 200) {
318	        setState(() {
319	          _blockedIds.add(userId);
320	          _users.removeWhere((u) => u.id == userId);
321	        });
322	      }
323	    } catch (_) {}
324	  }
325	
326	  Future<void> _refresh() async {
327	    setState(() {
328	      _users.clear();
329	      _page = 1;
330	      _hasMore = true;
331	      _errorMessage = null;
332	    });
333	    await _loadUsers();
334	  }
335	
336	  Widget _buildCard(UserCard user) {
337	    // Swap to Android emulator-accessible URL
338	    final photoUrl = user.photoUrl?.replaceFirst('http://0.0.0.0:8000', _baseUrl);
339	
340	    return ClipRRect(
341	      borderRadius: BorderRadius.circular(12),
342	      child: Stack(
343	        fit: StackFit.expand,
344	        children: [
345	          // Photo
346	          if (photoUrl != null)
347	            Image.network(
348	              photoUrl,
349	              fit: BoxFit.cover,
350	              headers: _token != null
351	                  ? {'Authorization': 'Bearer $_token'}
352	                  : {},
353	              errorBuilder: (_, __, ___) => _buildPlaceholder(user.username),
354	              loadingBuilder: (ctx, child, progress) {
355	                if (progress == null) return child;
356	                return _buildPlaceholder(user.username);
357	              },
358	            )
359	          else
360	            _buildPlaceholder(user.username),
361	
362	          // Username — top-left corner
363	          Positioned(
364	            top: 6,
365	            left: 6,
366	            child: Container(
367	              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 3),
368	              decoration: BoxDecoration(
369	                color: Colors.black.withOpacity(0.55),
370	                borderRadius: BorderRadius.circular(6),
371	              ),
372	              child: Text(
373	                user.username,
374	                style: const TextStyle(
375	                  color: Colors.white,
376	                  fontSize: 11,
377	                  fontWeight: FontWeight.w600,
378	                  shadows: [
379	                    Shadow(color: Colors.black87, blurRadius: 4),
380	                  ],
381	                ),
382	                maxLines: 1,
383	                overflow: TextOverflow.ellipsis,
384	              ),
385	            ),
386	          ),
387	
388	          // Age badge top-right
389	          if (user.age != null)
390	            Positioned(
391	              top: 6,
392	              right: 6,
393	              child: Container(
394	                padding:
395	                    const EdgeInsets.symmetric(horizontal: 5, vertical: 2),
396	                decoration: BoxDecoration(
397	                  color: Colors.black.withOpacity(0.65),
398	                  borderRadius: BorderRadius.circular(8),
399	                ),
400	                child: Text(
401	                  '${user.age}',
402	                  style: const TextStyle(
403	                    color: Colors.white,
404	                    fontSize: 11,
405	                    fontWeight: FontWeight.bold,
406	                  ),
407	                ),
408	              ),
409	            ),
410	
411	          // Block button — bottom-left
412	          Positioned(
413	            left: 6,
414	            bottom: 6,
415	            child: GestureDetector(
416	              onTap: () => _blockUser(user.id),
417	              child: Container(
418	                width: 32,
419	                height: 32,
420	                decoration: BoxDecoration(
421	                  color: Colors.black.withOpacity(0.65),
422	                  shape: BoxShape.circle,
423	                ),
424	                child: const Icon(
425	                  Icons.close,
426	                  color: Colors.white,
427	                  size: 18,
428	                ),
429	              ),
430	            ),
431	          ),
432	
433	          // Like button — bottom-right
434	          Positioned(
435	            right: 6,
436	            bottom: 6,
437	            child: GestureDetector(
438	              onTap: () => _likeUser(user),
439	              child: Container(
440	                width: 32,
441	                height: 32,
442	                decoration: BoxDecoration(
443	                  color: Colors.black.withOpacity(0.65),
444	                  shape: BoxShape.circle,
445	                ),
446	                child: Icon(
447	                  Icons.favorite,
448	                  color: _likedIds.contains(user.id)
449	                      ? Colors.red
450	                      : Colors.grey,
451	                  size: 18,
452	                ),
453	              ),
454	            ),
455	          ),
456	        ],
457	      ),
458	    );
459	  }
460	
461	  Widget _buildPlaceholder(String username) {
462	    return Container(
463	      color: Colors.blueAccent.withOpacity(0.15),
464	      child: Center(
465	        child: Text(
466	          username.isNotEmpty ? username[0].toUpperCase() : '?',
467	          style: const TextStyle(
468	            fontSize: 32,
469	            fontWeight: FontWeight.bold,
470	            color: Colors.blueAccent,
471	          ),
472	        ),
473	      ),
474	    );
475	  }
476	
477	  @override
478	  Widget build(BuildContext context) {
479	    return Scaffold(
480	      appBar: AppBar(
481	        title: const Text('Discover'),
482	        actions: [
483	          IconButton(
484	            icon: const Icon(Icons.settings_outlined, color: Colors.white),
485	            onPressed: () => Navigator.of(context).push(
486	              MaterialPageRoute(builder: (_) => const SettingsScreen()),
487	            ),
488	          ),
489	        ],
490	      ),
491	      body: RefreshIndicator(
492	        onRefresh: _refresh,
493	        child: _buildBody(),
494	      ),
495	    );
496	  }
497	
498	  Widget _buildBody() {
499	    if (_users.isEmpty && _isLoading) {
500	      return const Center(
501	          child: CircularProgressIndicator(color: Colors.blueAccent));
502	    }
503	
504	    if (_users.isEmpty && _errorMessage != null) {
505	      return Center(
506	        child: Padding(
507	          padding: const EdgeInsets.all(24),
508	          child: Column(
509	            mainAxisSize: MainAxisSize.min,
510	            children: [
511	              const Icon(Icons.error_outline, size: 48, color: Colors.redAccent),
512	              const SizedBox(height: 12),
513	              Text(_errorMessage!,
514	                  textAlign: TextAlign.center,
515	                  style: const TextStyle(color: Colors.redAccent)),
516	              const SizedBox(height: 16),
517	              ElevatedButton(
518	                  onPressed: _refresh, child: const Text('Retry')),
519	            ],
520	          ),
521	        ),
522	      );
523	    }
524	
525	    if (_users.isEmpty) {
526	      return const Center(
527	        child: Text('No users found.',
528	            style: TextStyle(color: Colors.grey, fontSize: 16)),
529	      );
530	    }
531	
532	    return GridView.builder(
533	      controller: _scrollController,
534	      padding: const EdgeInsets.all(8),
535	      itemCount: _users.length + (_hasMore ? 1 : 0),
536	      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
537	        crossAxisCount: 3,
538	        childAspectRatio: 3 / 4,
539	        crossAxisSpacing: 8,
540	        mainAxisSpacing: 8,
541	      ),
542	      itemBuilder: (context, index) {
543	        if (index >= _users.length) {
544	          // Loader tile
545	          return const Center(
546	              child: CircularProgressIndicator(color: Colors.blueAccent));
547	        }
548	        final user = _users[index];
549	        return GestureDetector(
550	          onTap: () {
551	            final photoUrl = (user.photoUrl
552	                    ?.replaceFirst('http://0.0.0.0:8000', _baseUrl)) ??
553	                '';
554	            Navigator.of(context).push(
555	              MaterialPageRoute(
556	                builder: (_) => ProfileScreen(
557	                  userId: user.id,
558	                  username: user.username,
559	                  age: user.age ?? 0,
560	                  sex: user.sex ?? 'Unknown',
561	                  photoUrl: photoUrl,
562	                ),
563	              ),
564	            );
565	          },
566	          child: _buildCard(user),
567	        );
568	      },
569	    );
570	  }
571	}
572	
573	// ── Ranking bottom sheet ───────────────────────────────────────────────────
574	
575	class _RankingSheet extends StatefulWidget {
576	  final List<_RankItem> items;
577	  final int newUserId;
578	  final String baseUrl;
579	  final String? token;
580	  final Future<void> Function(List<_RankItem>) onSave;
581	
582	  const _RankingSheet({
583	    required this.items,
584	    required this.newUserId,
585	    required this.baseUrl,
586	    required this.token,
587	    required this.onSave,
588	  });
589	
590	  @override
591	  State<_RankingSheet> createState() => _RankingSheetState();
592	}
593	
594	class _RankingSheetState extends State<_RankingSheet> {
595	  late List<_RankItem> _items;
596	  bool _saving = false;
597	  final ScrollController _scrollController = ScrollController();
