import 'package:flutter/material.dart';

class ProfileScreen extends StatelessWidget {
  final int userId;
  final String username;
  final int age;
  final String sex;
  final String photoUrl;

  const ProfileScreen({
    super.key,
    required this.userId,
    required this.username,
    required this.age,
    required this.sex,
    required this.photoUrl,
  });

  static const Color _bg = Color(0xFF12121C);
  static const Color _surface = Color(0xFF1E1E2E);
  static const Color _accent = Colors.blueAccent;

  @override
  Widget build(BuildContext context) {
    final screenHeight = MediaQuery.of(context).size.height;
    final photoHeight = screenHeight * 0.45;

    return Scaffold(
      backgroundColor: _bg,
      body: Column(
        children: [
          // ── Photo + floating back button ──────────────────────────────
          Stack(
            children: [
              SizedBox(
                width: double.infinity,
                height: photoHeight,
                child: _buildPhoto(),
              ),
              Positioned(
                top: MediaQuery.of(context).padding.top + 8,
                left: 12,
                child: GestureDetector(
                  onTap: () => Navigator.of(context).pop(),
                  child: Container(
                    padding: const EdgeInsets.all(8),
                    decoration: BoxDecoration(
                      color: Colors.black.withOpacity(0.70),
                      shape: BoxShape.circle,
                      boxShadow: [
                        BoxShadow(
                          color: Colors.black45,
                          blurRadius: 6,
                          offset: Offset(0, 2),
                        )
                      ],
                    ),
                    child: const Icon(
                      Icons.arrow_back_ios_new,
                      color: Colors.white,
                      size: 22,
                    ),
                  ),
                ),
              ),
            ],
          ),

          // ── Info panel ───────────────────────────────────────────────
          Expanded(
            child: Container(
              width: double.infinity,
              margin: const EdgeInsets.all(16),
              padding: const EdgeInsets.all(20),
              decoration: BoxDecoration(
                color: _surface,
                borderRadius: BorderRadius.circular(16),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // Username
                  Text(
                    username,
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 26,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                  const SizedBox(height: 12),

                  // Pill chips
                  Row(
                    children: [
                      _chip('Age $age'),
                      const SizedBox(width: 8),
                      _chip(sex),
                    ],
                  ),

                  const SizedBox(height: 16),
                  const Divider(color: Color(0xFF2E2E4E), thickness: 1),
                  const SizedBox(height: 16),

                  // Label rows
                  _labelRow('Age', '$age'),
                  const SizedBox(height: 10),
                  _labelRow('Sex', sex),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPhoto() {
    if (photoUrl.isNotEmpty) {
      return Image.network(
        photoUrl,
        fit: BoxFit.cover,
        width: double.infinity,
        errorBuilder: (_, __, ___) => _placeholder(),
        loadingBuilder: (ctx, child, progress) {
          if (progress == null) return child;
          return _placeholder();
        },
      );
    }
    return _placeholder();
  }

  Widget _placeholder() {
    return Container(
      color: _accent.withOpacity(0.15),
      child: Center(
        child: Text(
          username.isNotEmpty ? username[0].toUpperCase() : '?',
          style: const TextStyle(
            fontSize: 64,
            fontWeight: FontWeight.bold,
            color: _accent,
          ),
        ),
      ),
    );
  }

  Widget _chip(String label) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      decoration: BoxDecoration(
        color: _accent.withOpacity(0.15),
        borderRadius: BorderRadius.circular(20),
        border: Border.all(color: _accent.withOpacity(0.4)),
      ),
      child: Text(
        label,
        style: const TextStyle(
          color: _accent,
          fontSize: 13,
          fontWeight: FontWeight.w600,
        ),
      ),
    );
  }

  Widget _labelRow(String label, String value) {
    return Row(
      children: [
        SizedBox(
          width: 50,
          child: Text(
            label,
            style: const TextStyle(
              color: Color(0xFF8888AA),
              fontSize: 14,
            ),
          ),
        ),
        const SizedBox(width: 12),
        Text(
          value,
          style: const TextStyle(
            color: Colors.white,
            fontSize: 14,
            fontWeight: FontWeight.w500,
          ),
        ),
      ],
    );
  }
}
